from math import comb
def a(n):
    def ecw(m):
        def dfs(v, used):
            t = 0
            for u in range(m):
                e = v * m + u
                if used >> e & 1: t += 1
                else: t += dfs(u, used | (1 << e))
            return t
        return sum(dfs(u, 1 << (v*m+u)) for v in range(m) for u in range(m))
    return sum((-1)**(n-k) * comb(n-1,k-1) * ecw(k)//k for k in range(1,n+1))
print([a(n) for n in range(1, 6)]) # _Arkadeep Dutta_, Jun 07 2026

